INSERT INTO questions (subject, exam_type, question, option_a, option_b, option_c, option_d, option_e, correct_answer, explanation, year) VALUES 
('english', 'WAEC', 'Obi''s family is known for their audacity, so one is surprised at his _________.', 'cowardice', 'irritability', 'moodiness', 'insolence', NULL, 'A', 'The noun "audacity" refers to the action or attitude of being insolently bold, daring. The opposite is "cowardice", meaning showing fear and not having the guts to challenge something.', 2022), 
('english', 'WAEC', 'Bayo is careless in his ways while Tayo is _________.', 'lovable', 'meticulous', 'difficult', 'reserved', NULL, 'B', 'To be careless is to not be careful in what one does; to be care-free, nonchalant or indifferent to important things. The opposite is to be meticulous, careful, cautious or restrained.', 2022), 
('english', 'WAEC', 'In this country, the law against armed robbery is stringent whereas that against smoking in public places is _________.', 'accurate', 'complex', 'lax', 'easy', NULL, 'C', 'The adjective "stringent" describes rules or regulations that are strict, harsh, rigid or severe. The opposite is "lax" — not taken seriously or that can be maneuvered.', 2022), 
('english', 'WAEC', 'The purpose of education is to facilitate progress, not to _________ it.', 'prevent', 'impede', 'stampede', 'restrain', NULL, 'B', 'As used in the context of the given sentence, "facilitate" means to promote, accelerate, aid and enable progress. They also denote making the realization of progress faster. The opposite is "impede".', 2022), 
('english', 'WAEC', 'These days, many people concentrate on temporal things to the detriment of the _________.', 'tangible', 'durable', 'unchanging', 'spiritual', NULL, 'D', 'The context in which "temporal" is used is very important. While whatever is temporal does not last for a long time, in the expression "These days, many people concentrate on temporal things" the adjective means: worldly, earthly, mundane or profane. The opposite is "divine".', 2022), 
('english', 'WAEC', 'While your parents are liberal in their views, mine are _________.', 'strict', 'intimidating', 'conservative', 'discerning', NULL, 'C', 'As used in the given sentence, "liberal" means to be open-minded and always progressive, forward-thinking and being able to shift grounds in your approach to issues; free thinking. The opposite is "conservative".', 2022), 
('english', 'WAEC', 'The judge expected direct answers but the accused was _________.', 'illusive', 'secretive', 'delusive', 'evasive', NULL, 'D', 'To be "evasive" in a discussion means to avoid providing a clear, straightforward and easily understood answers. A response that is indirect, vague or equivocal is evasive.', 2022), 
('english', 'WAEC', 'Kofi is generous, whereas his wife is _________.', 'sparing', 'stingy', 'unkind', 'harsh', NULL, 'B', 'The opposite of "generous" as used in this sentence is "stingy". To be generous means to be willing to give more than is usual or expected. The adjective stingy describes a person that is unwilling to spend money or let others benefit from what they have.', 2022), 
('english', 'WAEC', 'His manners are uncouth, while his wife''s are _________.', 'clever', 'classic', 'refined', 'purified', NULL, 'C', 'To be uncouth means to be rude, bad-mannered or disrespectful. The opposite would be to be "refined" — meaning to be very polite and showing courtesy, etiquette or the knowledge of social rules.', 2022), 
('english', 'WAEC', 'The peak of Mount Everest is about six miles from its _________.', 'base', 'source', 'depth', 'root', NULL, 'A', 'The top, summit or pinnacle of a mountain or hill is called the peak, at the bottom where it meets flat land is called the base.', 2022), 
('english', 'WAEC', 'The recent floods in some countries have _________ many lives.', 'claimed', 'drowned', 'buried', 'injured', NULL, 'A', 'The adjective "claimed" is appropriate, to mean many have died as a result of the floods.', 2022), 
('english', 'WAEC', 'He does not smoke so the gift of an ashtray will not be quite _________.', 'admirable', 'applicable', 'appropriate', 'attractive', NULL, 'C', 'The adjective "appropriate" in the sentence is "to meet the need of someone and that will be appreciated by the latter". The word that best meets this description is "appropriate".', 2022), 
('english', 'WAEC', 'The reviewer did an excellent job at the book _________.', 'launch', 'premiere', 'session', 'briefing', NULL, 'A', 'The sentence is correct as: "The reviewer did an excellent job at the book launch." Book launch is an all-invited event wherein a newly published book, often a debut, is presented to the public.', 2022), 
('english', 'WAEC', 'The governor filed an _________ against the ruling of the tribunal.', 'injunction', 'objection', 'application', 'appeal', NULL, 'D', 'The sentence is correct as: "The governor filed an appeal against the ruling of the tribunal." Note that an appeal is a case your file to the appeal court to revisit and re-address your case.', 2022), 
('english', 'WAEC', 'At the terminus, all passengers on the train will have to _________.', 'alight', 'claimed', 'descend', 'dismount', NULL, 'A', 'The verb "disembark" is the register to referring to getting off a train, airplane or ship. Note that "alight" is the verb for getting of a car/vehicle or carriage.', 2022), 
('english', 'WAEC', 'Reading the _________ of the famous king, one would see that he had many things to hide.', 'memoirs', 'chronicles', 'life', 'monument', NULL, 'A', 'The appropriate word is "memoirs". A memoir is a personal account of someone''s experiences, observations, exposures and life around the things he had witnessed, seen and done.', 2022), 
('english', 'WAEC', 'The smaller boys had always drawn back in fear when the bully raised a fist, but this time they did not _________.', 'advance', 'agree', 'retaliate', 'recoil', NULL, 'D', 'The sentence is correct as: "The smaller boys had always drawn back in fear when the bully raised a fist, but this time they did not recoil." To recoil in fear means to retreat, pull back or withdraw.', 2022), 
('english', 'WAEC', 'The old man prayed for the _________ of his sins before he died.', 'omission', 'commission', 'permission', 'remission', NULL, 'D', '"Remission" means forgiveness of an offense, a pardon of sins. The Catholics say "... don of sins where a sinner must spend a long time to gain remission before going to paradise."', 2022), 
('english', 'WAEC', 'Inflation has caused the cost of goods to _________.', 'escalate', 'ascend', 'intensify', 'progress', NULL, 'A', 'The sentence is correct as: "Inflation has caused the cost of goods to escalate." The verb "escalate" notes a sudden sharp increase in the prices of products either because the supply is quite lower than what is demanded or the cost of producing or importing them has increased.', 2022), 
('english', 'WAEC', 'The economy of the country has remained _________ despite the crisis.', 'strong', 'realistic', 'tough', 'firm', NULL, 'A', 'A strong economy is the one that cannot be affected poorly by socio-political crises or unexpected epidemics; an economy that records high rate of growth or steady output.', 2022), 
('english', 'WAEC', 'The principal raised eyebrows at the student''s explanation. This means that the principal was:', 'unhappy about the explanation', 'rejected the explanation', 'considered the explanation', 'surprised by the explanation', NULL, 'D', '"Raise eyebrows" means to check or surprise people. The principal raised eyebrows at the explanation means he was surprised.', 2022), 
('english', 'WAEC', 'Mary made a clean breast of everything. This means that Mary:', 'won everyone over', 'told the whole truth', 'did everything efficiently', 'changed the way things were done', NULL, 'B', '"Make a clean breast of something" means to confess something bad that you have done in order not to feel guilty or bad.', 2022), 
('english', 'WAEC', 'Had it not rained, I would have visited you. This means that:', 'I visited you', 'it did not rain and so I visited you', 'it rained so I did not visit you', 'it did not visit you', NULL, 'C', 'The sentence is a conditional subjunctive statement that expresses an action that did not happen when it was due for occurrence, because the condition was not fulfilled.', 2022), 
('english', 'WAEC', 'Bola invited Joe and me as a sharp slap. When she snapped my head off, it means that she:', 'rudely interrupted me', 'hissed at me', 'ordered me to stop talking', 'severely criticised me', NULL, 'A', '"Snap someone''s head off" means to answer someone in a rude or unreasonably angry way; to yell at or talk very angrily.', 2022), 
('english', 'WAEC', 'Franca''s behaviour towards Edward leaves much to be desired. This means that Franca''s behaviour was:', 'unsatisfactory', 'appreciated', 'commendable', 'unexpected', NULL, 'A', '"Leaves much to be desired" is used to mean something is not good at all or it is not close to being good.', 2022), 
('english', 'WAEC', 'The teacher truly had his heart in the right place. This means that he was:', 'kind and considerate', 'sharp and modest', 'simple and modest', 'focused and direct', NULL, 'A', '"Have one''s heart in the right place" means they are kind, considerate, and generous.', 2022), 
('english', 'WAEC', 'Only teachers could afford a car. This means that:', 'teachers could afford a car and nothing else', 'teachers and others could afford a car', 'nobody else could afford a car', 'few teachers could afford a car', NULL, 'C', 'The expression "Only teachers could afford a car" means teachers and nobody else could afford a car.', 2022), 
('english', 'WAEC', 'The night watchman was given the marching orders because of his negligence. This means that he was:', 'promoted', 'dismissed', 'counselled', 'suspended', NULL, 'B', '"Marching orders" means to be relieved and dismissed from duties; to be sacked.', 2022), 
('english', 'WAEC', 'My friend is as dull as ditchwater. This means that my friend is:', 'dark in complexion', 'extremely boring', 'not intelligent', 'not a troublemaker', NULL, 'B', '"As dull as ditchwater" means not social, communicative and engaging. Extremely boring or very uninteresting.', 2022), 
('english', 'WAEC', 'The director sees Tim as the joker in the pack. This means the director considers Tim to be:', 'unpredictable', 'humorous', 'nonchalant', 'unruly', NULL, 'A', '"The joker in the pack" is someone, a situation or factor likely to have an unpredictable effect on events.', 2022), 
('english', 'WAEC', 'It was strategic of the government to boycott classes. The word "strategic" means:', 'tactical', 'premeditated', 'well-thought off', 'planned', NULL, 'A', 'The adjective "strategic" means tactical, premeditated, well-thought off or calculated.', 2022), 
('english', 'WAEC', 'The proscription of the political parties was one of the steps taken by the military. The appropriate synonym for "proscription" is:', 'banning', 'removal', 'expulsion', 'exclusion', NULL, 'A', 'The appropriate synonym for "proscription" as used in the given context is banning. Other synonyms are: prohibition, outlawing and exclusion.', 2022), 
('english', 'WAEC', 'Farmers sometimes go through the frustrating experience of having to watch their produce rot. The word "frustrating" means:', 'disheartening', 'dismaying', 'annoying', 'frightening', NULL, 'C', 'The adjective "frustrating" means annoying, vexing, infuriating, provoking, exasperating and bothersome.', 2022), 
('english', 'WAEC', 'The acrobatic displays left the spectators stunned. "Stunned" means:', 'amused', 'elated', 'astonished', 'enticed', NULL, 'C', '"Stunned" in the sentence means "astonished". Other similar words are: amazed, surprised, astounded, dazed and impressed.', 2022), 
('english', 'WAEC', 'Binetou looked quite resplendent in that red dress. "Resplendent" means:', 'expensive', 'stunning', 'conspicuous', 'respectable', NULL, 'B', '"Resplendent" means attractive, impressive, sive, colorful, shiny, stunning, dazzling, splendid, glittering, magnificent.', 2022), 
('english', 'WAEC', 'It is foolish to depend entirely on mundane things. "Mundane" means:', 'imported', 'material', 'attractive', 'expensive', NULL, 'B', 'Context is very important in interpreting the meaning of a word. The adjective "mundane" as used in this sentence means physical, worldly and earthly. Examples: The love of mundane things is a distraction to one''s spiritual commitment.', 2022), 
('english', 'WAEC', 'Only a pragmatic approach will solve this problem. "Pragmatic" means:', 'constant', 'careful', 'practical', 'drastic', NULL, 'C', 'The adjective "pragmatic" as used in the sentence means practical, realistic, logical, rational and critical.', 2022), 
('english', 'WAEC', 'The governor rebutted all the allegations against him. "Rebutted" means:', 'rejected', 'removed', 'revoked', 'refuted', NULL, 'D', 'The verb "rebutted" in the sentence denotes refuted, disproved, denied and contradicted. To rebut means to deny the truth of something, especially by presenting arguments that disprove it.', 2022), 
('english', 'WAEC', 'He was jailed for failing to obey the court injunction. "Injunction" means:', 'a law', 'an order', 'proceedings', 'fine', NULL, 'B', 'An injunction is a pronouncement, decree, judgment or order by a court of law to refrain someone or a group from doing a particular act.', 2022), 
('english', 'WAEC', 'The World Bank made funds available to the government for poverty alleviation. "Alleviation" means:', 'reduction', 'removal', 'termination', 'elimination', NULL, 'A', 'Alleviation means the act of reducing, relieving or mitigating a challenge or anything unpleasant, in the given case, poverty.', 2022), 
('english', 'WAEC', 'The two players protested against the twice-weekly fitness practice. The word or group of words that best completes the sentence is:', 'fitness twice-weekly practice', 'practice fitness twice-weekly', 'twice-weekly practice fitness', 'twice-weekly fitness practice', NULL, 'D', 'In the noun phrase "twice-weekly fitness practice", the noun "practice" is the headword which other words function as adjectives to qualify.', 2022), 
('english', 'WAEC', 'If I _________ what actually happened, I would have punished him.', 'had heard', 'have had', 'had had', 'have heard', NULL, 'A', 'The sentence is a subjunctive sentence expression an action that did not happen when it was due. It is correct as "If I had heard what actually happened, I would have punished him."', 2022), 
('english', 'WAEC', 'She was certainly going to the cinema, ________?', 'isn''t she', 'isn''t it', 'wasn''t it', 'wasn''t she', NULL, 'D', 'In question tag, it is the auxiliary verb of the statement that is used to generate the tag following. If the auxiliary verb appears in the negative, that of the tag will be positive and vice versa.', 2022), 
('english', 'WAEC', 'Their _________ house is by the side of the road.', 'father-in-law''s', 'father''s-in-law', 'fathers''-in-law', 'father-in-laws', NULL, 'A', 'In possessive, apostrophe (s) or s'' only falls on a possessive noun or genitive (s), only a possessive noun or genitive.', 2022), 
('english', 'WAEC', 'He _________ his ideas very clearly at meetings.', 'puts out', 'puts across', 'puts away', 'puts in', NULL, 'B', '"Put across" means to communicate an idea clearly so that people understand it.', 2022), 
('english', 'WAEC', 'Remember to return it to Ruth; _________ it belongs to her.', 'after all', 'above all', 'first of all', 'in all', NULL, 'A', '"After all" means used to say that something is true or possible despite what has been said or thought before.', 2022);
